tlDataChunk*
tlFlexibleJointChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Simulation::Flexible::JOINT_PARAMETERS:
        dch = new tlFlexibleJointParametersChunk(&ch);
        break;
    case Simulation::Flexible::JOINT_LAMBDA:
        dch = new tlFlexibleLambdaJointParamChunk(&ch);
        break;
    case Simulation::Flexible::JOINT_DEFINITION:
        dch = new tlFlexibleJointDefinitionChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

