int tlFlexibleJointParametersChunk::sortPriority = -1;

tlFlexibleJointParametersChunk::tlFlexibleJointParametersChunk()
{
    Init();
}

tlFlexibleJointParametersChunk::tlFlexibleJointParametersChunk(const tlFlexibleJointParametersChunk& ch)
{
    Init();
    *this = ch;
}

tlFlexibleJointParametersChunk::~tlFlexibleJointParametersChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlFlexibleJointParametersChunk::tlFlexibleJointParametersChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Flexible::JOINT_PARAMETERS);
    ident = Simulation::Flexible::JOINT_PARAMETERS;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    stretch1dkf = f->GetFloat();
    stretch1dkd = f->GetFloat();
    bend1dkf = f->GetFloat();
    bend1dkd = f->GetFloat();
    wind1dkf = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::JOINT_PARAMETERS);
    }
}

void
tlFlexibleJointParametersChunk::Init()
{
    ident = Simulation::Flexible::JOINT_PARAMETERS;
    name = NULL;
    stretch1dkf = 0.0f;
    stretch1dkd = 0.0f;
    bend1dkf = 0.0f;
    bend1dkd = 0.0f;
    wind1dkf = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Flexible::JOINT_PARAMETERS);
    }
}

long 
tlFlexibleJointParametersChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( stretch1dkf );
    s += sizeof( stretch1dkd );
    s += sizeof( bend1dkf );
    s += sizeof( bend1dkd );
    s += sizeof( wind1dkf );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlFlexibleJointParametersChunk&
tlFlexibleJointParametersChunk::operator=(const tlFlexibleJointParametersChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    stretch1dkf = a.stretch1dkf;
    stretch1dkd = a.stretch1dkd;
    bend1dkf = a.bend1dkf;
    bend1dkd = a.bend1dkd;
    wind1dkf = a.wind1dkf;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlFlexibleJointParametersChunk::operator==(const tlDataChunk& a)
{

    const tlFlexibleJointParametersChunk* aptr = dynamic_cast<const tlFlexibleJointParametersChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(stretch1dkf == aptr->stretch1dkf))
    {
        return false;
    }
    if(!(stretch1dkd == aptr->stretch1dkd))
    {
        return false;
    }
    if(!(bend1dkf == aptr->bend1dkf))
    {
        return false;
    }
    if(!(bend1dkd == aptr->bend1dkd))
    {
        return false;
    }
    if(!(wind1dkf == aptr->wind1dkf))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlFlexibleJointParametersChunk::NameCompare(const tlDataChunk& a)
{

    const tlFlexibleJointParametersChunk* aptr = dynamic_cast<const tlFlexibleJointParametersChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


