void
tlFlexibleJointParametersChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutFloat(stretch1dkf);
        f->PutFloat(stretch1dkd);
        f->PutFloat(bend1dkf);
        f->PutFloat(bend1dkd);
        f->PutFloat(wind1dkf);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlFlexibleJointParametersChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlFlexibleJointParametersChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name        = \"%s\"\n",indent,"",name);
    printf("%*s  Stretch1Dkf = %f\n",indent,"",stretch1dkf);
    printf("%*s  Stretch1Dkd = %f\n",indent,"",stretch1dkd);
    printf("%*s  Bend1Dkf    = %f\n",indent,"",bend1dkf);
    printf("%*s  Bend1Dkd    = %f\n",indent,"",bend1dkd);
    printf("%*s  Wind1DKf    = %f\n",indent,"",wind1dkf);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlFlexibleJointParametersChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name       \n",indent,"",name);
    printf("%*s  float %12f # Stretch1Dkf\n",indent,"",stretch1dkf);
    printf("%*s  float %12f # Stretch1Dkd\n",indent,"",stretch1dkd);
    printf("%*s  float %12f # Bend1Dkf   \n",indent,"",bend1dkf);
    printf("%*s  float %12f # Bend1Dkd   \n",indent,"",bend1dkd);
    printf("%*s  float %12f # Wind1DKf   \n",indent,"",wind1dkf);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

