void
tlFlexibleJointDefinitionChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutPString(name);
        f->PutPString(parametersname);
        f->PutPString(restingposparametersname);
        f->PutPString(connectionparametersname);
        f->PutWord(gravity);
        f->PutWord(simmethod);
        f->PutWord(userestingpos);
        f->PutWord(restmethod);
        f->PutWord(updatemethod);
        f->PutWord(usevirtualjoint);
        f->PutWord(solver);
        f->PutFloat(externaldensityfactor);
        f->PutLong(numjointindex);
    for(i = 0; i < numjointindex ; i++)
    {
        f->PutLong(flexiblejointindex[i]);
    }
        f->PutLong(numfixjointindex);
    for(i = 0; i < numfixjointindex ; i++)
    {
        f->PutLong(flexiblefixjointindex[i]);
    }
        f->PutLong(numendofbranchindex);
    for(i = 0; i < numendofbranchindex ; i++)
    {
        f->PutLong(endofbranchindex[i]);
    }
        f->PutLong(numconnection);
    for(i = 0; i < numconnection ; i++)
    {
        flexiblejointconnection[i].Write(f);
    }
        f->PutLong(numhinge);
    for(i = 0; i < numhinge ; i++)
    {
        flexiblejointhinge[i].Write(f);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlFlexibleJointDefinitionChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlFlexibleJointDefinitionChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name                     = \"%s\"\n",indent,"",name);
    printf("%*s  ParametersName           = \"%s\"\n",indent,"",parametersname);
    printf("%*s  RestingPosParametersName = \"%s\"\n",indent,"",restingposparametersname);
    printf("%*s  ConnectionParametersName = \"%s\"\n",indent,"",connectionparametersname);
    printf("%*s  Gravity                  = %d\n",indent,"",gravity);
    printf("%*s  SimMethod                = %d\n",indent,"",simmethod);
    printf("%*s  UseRestingPos            = %d\n",indent,"",userestingpos);
    printf("%*s  RestMethod               = %d\n",indent,"",restmethod);
    printf("%*s  UpdateMethod             = %d\n",indent,"",updatemethod);
    printf("%*s  UseVirtualJoint          = %d\n",indent,"",usevirtualjoint);
    printf("%*s  Solver                   = %d\n",indent,"",solver);
    printf("%*s  ExternalDensityFactor    = %f\n",indent,"",externaldensityfactor);
    printf("%*s  NumJointIndex            = %ld\n",indent,"",numjointindex);
    printf("%*s  FlexibleJointIndex:\n",indent,"");
    for( i=0; i < numjointindex; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,flexiblejointindex[i]);
    }
    printf("%*s  NumFixJointIndex         = %ld\n",indent,"",numfixjointindex);
    printf("%*s  FlexibleFixJointIndex:\n",indent,"");
    for( i=0; i < numfixjointindex; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,flexiblefixjointindex[i]);
    }
    printf("%*s  NumEndOfBranchIndex      = %ld\n",indent,"",numendofbranchindex);
    printf("%*s  EndOfBranchIndex:\n",indent,"");
    for( i=0; i < numendofbranchindex; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,endofbranchindex[i]);
    }
    printf("%*s  NumConnection            = %ld\n",indent,"",numconnection);
    printf("%*s  FlexibleJointConnection:\n",indent,"");
    for( i=0; i < numconnection; i++)
    {
         flexiblejointconnection[i].Print(i, indent + 4);
    }
    printf("%*s  NumHinge                 = %ld\n",indent,"",numhinge);
    printf("%*s  FlexibleJointHinge:\n",indent,"");
    for( i=0; i < numhinge; i++)
    {
         flexiblejointhinge[i].Print(i, indent + 4);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

