    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  int   %12ld # NumConnection           \n",indent,"",numconnection);
    printf("%*s  # FlexibleJointConnection \n",indent,""); 
    for( i=0; i < numconnection; i++)
    {
         flexiblejointconnection[i].PrintFormatted(i,indent+4);
    }
    printf("%*s  int   %12ld # NumHinge                \n",indent,"",numhinge);
